import React from 'react';
import Trade from './Trade';

const trades = [
    {id:'ID', stock:'STOCK', method:'Method', quantity:'Q', profitLoss:'P'},
    {id:1, stock:'MES', method:'Bollinger', quantity:1, profitLoss:1},
    {id:2, stock:'MES', method:'--S & R--', quantity:2, profitLoss:3}
]

function TradeList() {
    return(
        <div>
              
            { trades.map(trade => {
                return <Trade key={trade.id} trade={trade}/>
            }) }       
        </div>
    )
}

export default TradeList;
